import{_ as a,o as e,c as s,ag as o}from"./chunks/framework.1N8rnUr9.js";const n="/tubebay/assets/library-sync-button.dtDjZgCB.png",r="/tubebay/assets/library-sync-progress.Duh6fHi5.png",i="/tubebay/assets/dashboard-sync-status.kwkh2y2l.png",b=JSON.parse('{"title":"Syncing Your Library","description":"","frontmatter":{},"headers":[],"relativePath":"guide/sync-library.md","filePath":"guide/sync-library.md","lastUpdated":1775898496000}'),l={name:"guide/sync-library.md"};function c(u,t,y,d,h,g){return e(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="syncing-your-library" tabindex="-1">Syncing Your Library <a class="header-anchor" href="#syncing-your-library" aria-label="Permalink to &quot;Syncing Your Library&quot;">​</a></h1><p>Once connected, TubeBay&#39;s primary job is to keep a local cache of your YouTube video library within WordPress. This makes searching and mapping videos extremely fast without hitting YouTube&#39;s rate limits constantly.</p><h2 id="automatic-sync" tabindex="-1">Automatic Sync <a class="header-anchor" href="#automatic-sync" aria-label="Permalink to &quot;Automatic Sync&quot;">​</a></h2><p>By default, TubeBay automatically checks for new videos every <strong>12 hours</strong>.</p><ul><li><strong>How it works:</strong> A background process (WP-Cron) triggers a request to the YouTube API.</li><li><strong>What is fetched:</strong> Your latest 50 uploads.</li><li><strong>Cache Duration:</strong> You can adjust the sync frequency in <strong>Settings &gt; Advanced</strong>.</li></ul><div class="tip custom-block"><p class="custom-block-title">Background Processing</p><p>The automatic sync happens in the background. If you just uploaded a video to YouTube and want to see it immediately in TubeBay, use the <strong>Manual Sync</strong> option.</p></div><h2 id="manual-sync" tabindex="-1">Manual Sync <a class="header-anchor" href="#manual-sync" aria-label="Permalink to &quot;Manual Sync&quot;">​</a></h2><p>If you need to fetch your latest videos immediately, you can trigger a manual sync.</p><ol><li>Go to <strong>TubeBay &gt; Library</strong>.</li><li>Click the <strong>Sync Library</strong> button at the top right.</li></ol><p><img src="'+n+'" alt="Sync Library Button"></p><ol start="3"><li>Wait for the process to complete. You will see a notification once the new videos are cached.</li></ol><p><img src="'+r+'" alt="Sync Progress and Success"></p><h2 id="sync-status" tabindex="-1">Sync Status <a class="header-anchor" href="#sync-status" aria-label="Permalink to &quot;Sync Status&quot;">​</a></h2><p>You can monitor the sync status in the <strong>TubeBay Dashboard</strong>.</p><p><img src="'+i+'" alt="Dashboard Sync Status"></p><ul><li><strong>Connected:</strong> The last sync was successful.</li><li><strong>Failed:</strong> There was an error during the last sync attempt (usually due to an expired token or API quota).</li><li><strong>Last Sync:</strong> Displays the timestamp of the most recent successful update.</li></ul><h2 id="troubleshooting-sync" tabindex="-1">Troubleshooting Sync <a class="header-anchor" href="#troubleshooting-sync" aria-label="Permalink to &quot;Troubleshooting Sync&quot;">​</a></h2><ul><li><strong>Quota Exceeded:</strong> YouTube limits the number of requests per day. If you reach this limit, sync will pause until the next day.</li><li><strong>Invalid Credentials:</strong> If your OAuth token expires or your API key is deleted, the sync will fail. You will need to reconnect your account.</li></ul>',18)])])}const m=a(l,[["render",c]]);export{b as __pageData,m as default};
